class Solution:
    def findSubsequences(self, nums):
        n = len(nums)
        found = set()
        for mask in range(1, 1 << n):
            seq = [nums[i] for i in range(n) if (mask >> i) & 1]
            if len(seq) < 2:
                continue
            ok = all(seq[i] <= seq[i+1] for i in range(len(seq) - 1))
            if ok:
                found.add(tuple(seq))
        return [list(t) for t in found]

