class Solution:
    def findSubsequences(self, nums):
        res = []
        path = []
        n = len(nums)
        def bt(start):
            if len(path) >= 2:
                res.append(path[:])
            used = set()
            for i in range(start, n):
                if nums[i] in used:
                    continue
                if path and nums[i] < path[-1]:
                    continue
                used.add(nums[i])
                path.append(nums[i])
                bt(i + 1)
                path.pop()
        bt(0)
        return res

