var findSubsequences = function(nums) {
    const res = [];
    const path = [];
    const n = nums.length;
    const bt = (start) => {
        if (path.length >= 2) res.push(path.slice());
        const used = new Set();
        for (let i = start; i < n; i++) {
            if (used.has(nums[i])) continue;
            if (path.length && nums[i] < path[path.length - 1]) continue;
            used.add(nums[i]);
            path.push(nums[i]);
            bt(i + 1);
            path.pop();
        }
    };
    bt(0);
    return res;
};
